# Mathematical approach
# Only ONE way to get GGBBB out of 2^5 = 32 outcomes
prob_ggbbb = 1 / (2**5)
print(f"P(GGBBB) = 1/32 = {prob_ggbbb}")

# Verification by enumeration
S = ['G', 'B']
count_ggbbb = 0
total = 0

for c1 in S:
    for c2 in S:
        for c3 in S:
            for c4 in S:
                for c5 in S:
                    total += 1
                    sequence = c1 + c2 + c3 + c4 + c5
                    if sequence == 'GGBBB':
                        count_ggbbb += 1
                        print(f"Found: {sequence}")

print(f"Verification: {count_ggbbb}/{total} = {count_ggbbb/total}")
